import sys
def fill_matrix(n: int) -> list[list[int]]:
    col_used = [set() for _ in range(n)]
    grid = []
    for i in range(n):
        row: list[int | None] = [None] * n
        used_in_row: set[int] = set()
        def backtrack(j: int) -> bool:
            if j == n:
                return True
            for v in range(n):
                if v not in used_in_row and v not in col_used[j]:
                    row[j] = v
                    used_in_row.add(v)
                    if backtrack(j + 1):
                        return True
                    used_in_row.remove(v)
                    row[j] = None
            return False
        backtrack(0)
        grid.append(row)
        for j, v in enumerate(row):
            col_used[j].add(v)
    return grid
n = int(sys.argv[1])
for order in range(1, n + 1):
    print(fill_matrix(order))

